import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { SearchIcon, CheckCircleIcon, XCircleIcon } from '@heroicons/react/24/outline';
import { useLocation } from 'react-router-dom';

const VerifyCertificate = () => {
  const { t } = useTranslation();
  const location = useLocation();
  const [certificateId, setCertificateId] = useState(
    new URLSearchParams(location.search).get('id') || ''
  );
  const [verificationStatus, setVerificationStatus] = useState(null);
  const [loading, setLoading] = useState(false);

  // 模拟验证证书
  const verifyCertificate = e => {
    e.preventDefault();
    if (!certificateId.trim()) return;

    setLoading(true);
    // 模拟API调用
    setTimeout(() => {
      // 使用固定的证书ID进行演示，实际应该从API获取
      const isValid = ['CERT-1234', 'CERT-5678', 'CERT-9012'].includes(certificateId);
      setVerificationStatus({
        valid: isValid,
        details: isValid
          ? {
              id: certificateId,
              name: 'John Doe',
              course: 'Business Administration',
              issueDate: '2023-05-15',
              expiryDate: '2028-05-15',
              status: 'Active',
            }
          : null,
      });
      setLoading(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen bg-gray-50 pt-24 pb-12">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center">
          <h1 className="text-3xl font-extrabold text-gray-900 sm:text-4xl">
            {t('verifyCertificatePage.title')}
          </h1>
          <p className="mt-3 max-w-2xl mx-auto text-xl text-gray-900 sm:mt-4">
            {t('verifyCertificatePage.subtitle')}
          </p>
        </div>

        <div className="mt-12 max-w-3xl mx-auto">
          <div className="bg-white overflow-hidden shadow rounded-lg">
            <div className="px-4 py-5 sm:p-6">
              <form onSubmit={verifyCertificate} className="space-y-6">
                <div>
                  <label
                    htmlFor="certificate-id"
                    className="block text-sm font-medium text-gray-900"
                  >
                    {t('verifyCertificatePage.form.certificateIdLabel')}
                  </label>
                  <div className="mt-1 flex rounded-md shadow-sm">
                    <input
                      type="text"
                      name="certificate-id"
                      id="certificate-id"
                      className="focus:ring-[#003087] focus:border-[#003087] flex-1 block w-full rounded-md sm:text-sm border-gray-300"
                      placeholder={t('verifyCertificatePage.form.certificateIdPlaceholder')}
                      value={certificateId}
                      onChange={e => setCertificateId(e.target.value)}
                    />
                  </div>
                </div>

                <div>
                  <button
                    type="submit"
                    className="w-full inline-flex justify-center items-center py-3 px-5 border border-transparent rounded-md shadow-lg text-lg font-bold text-white bg-[#003087] hover:bg-[#002266] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#003087]"
                    disabled={loading}
                  >
                    {loading ? (
                      <>
                        <svg
                          className="animate-spin -ml-1 mr-3 h-5 w-5 text-white"
                          xmlns="http://www.w3.org/2000/svg"
                          fill="none"
                          viewBox="0 0 24 24"
                        >
                          <circle
                            className="opacity-25"
                            cx="12"
                            cy="12"
                            r="10"
                            stroke="currentColor"
                            strokeWidth="4"
                          ></circle>
                          <path
                            className="opacity-75"
                            fill="currentColor"
                            d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                          ></path>
                        </svg>
                        {t('verifyCertificatePage.form.verifyingButton')}
                      </>
                    ) : (
                      <>
                        <SearchIcon className="-ml-1 mr-2 h-5 w-5 text-white" aria-hidden="true" />
                        {t('verifyCertificatePage.form.verifyButton')}
                      </>
                    )}
                  </button>
                </div>
              </form>

              {/* 验证结果 */}
              {verificationStatus && (
                <div className="mt-8">
                  <div
                    className={`rounded-md p-4 ${verificationStatus.valid ? 'bg-green-50' : 'bg-red-50'}`}
                  >
                    <div className="flex">
                      <div className="flex-shrink-0">
                        {verificationStatus.valid ? (
                          <CheckCircleIcon className="h-5 w-5 text-green-600" aria-hidden="true" />
                        ) : (
                          <XCircleIcon className="h-5 w-5 text-red-600" aria-hidden="true" />
                        )}
                      </div>
                      <div className="ml-3">
                        <h3
                          className={`text-sm font-bold ${verificationStatus.valid ? 'text-green-900' : 'text-red-900'}`}
                        >
                          {verificationStatus.valid
                            ? t('verifyCertificatePage.results.valid')
                            : t('verifyCertificatePage.results.invalid')}
                        </h3>
                      </div>
                    </div>
                  </div>

                  {verificationStatus.valid && verificationStatus.details && (
                    <div className="mt-6 border-t border-gray-200 pt-6">
                      <h3 className="text-lg font-bold text-gray-900">
                        {t('verifyCertificatePage.results.certificateDetails')}
                      </h3>
                      <div className="mt-4 grid grid-cols-1 gap-y-6 sm:grid-cols-2 sm:gap-x-4">
                        <div>
                          <dt className="text-sm font-medium text-gray-700">
                            {t('verifyCertificatePage.results.certificateId')}
                          </dt>
                          <dd className="mt-1 text-sm text-gray-900">
                            {verificationStatus.details.id}
                          </dd>
                        </div>
                        <div>
                          <dt className="text-sm font-medium text-gray-700">
                            {t('verifyCertificatePage.results.name')}
                          </dt>
                          <dd className="mt-1 text-sm text-gray-900">
                            {verificationStatus.details.name}
                          </dd>
                        </div>
                        <div>
                          <dt className="text-sm font-medium text-gray-700">
                            {t('verifyCertificatePage.results.course')}
                          </dt>
                          <dd className="mt-1 text-sm text-gray-900">
                            {verificationStatus.details.course}
                          </dd>
                        </div>
                        <div>
                          <dt className="text-sm font-medium text-gray-700">
                            {t('verifyCertificatePage.results.issueDate')}
                          </dt>
                          <dd className="mt-1 text-sm text-gray-900">
                            {verificationStatus.details.issueDate}
                          </dd>
                        </div>
                        <div>
                          <dt className="text-sm font-medium text-gray-700">
                            {t('verifyCertificatePage.results.expiryDate')}
                          </dt>
                          <dd className="mt-1 text-sm text-gray-900">
                            {verificationStatus.details.expiryDate}
                          </dd>
                        </div>
                        <div>
                          <dt className="text-sm font-medium text-gray-700">
                            {t('verifyCertificatePage.results.status')}
                          </dt>
                          <dd className="mt-1 text-sm text-gray-900">
                            <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                              {verificationStatus.details.status}
                            </span>
                          </dd>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default VerifyCertificate;
